#include <iostream>
#include <string>

class Light
{
    std::string m_roomName;

public:
    Light(const std::string& roomName)
        : m_roomName{roomName}
    {
        std::cout << "Light created for " << m_roomName << '\n';
    }

    ~Light()
    {
        std::cout << "Light destroyed for " << m_roomName << '\n';
    }

    void turnOn() const
    {
        std::cout << m_roomName << ": light is on" << '\n';
    }
};

class Room
{
    Light m_light;

public:
    Room(const std::string& name)
        : m_light{name}
    {
    }

    void illuminate() const
    {
        m_light.turnOn();
    }
};

int main()
{
    std::string name{};
    std::cin >> name;

    Room room{name};
    room.illuminate();

    return 0;
}

